import { VectorStoreIndex, ContextChatEngine } from 'llamaindex';
import { verify } from '@vex/sdk';

// Assume index loaded from e-commerce data
const index = await VectorStoreIndex.fromDocuments(productDocs);
const queryEngine = index.asQueryEngine();

async function safeRecommend(query: string) {
  const response = await queryEngine.query({ query });
  const result = await verify({
    input: response.response,
    rules: [
      {
        name: 'stock_accuracy',
        type: 'factual_consistency',
        threshold: 0.95,
        context: response.sourceNodes.map(n => n.node.text)
      },
      {
        name: 'no_hallucination',
        type: 'groundedness',
        sources: response.sourceNodes
      }
    ]
  });
  return result.passed ? response.response : 'Blocked: Unavailable product';
}

safeRecommend('Recommend laptops under $1000').then(console.log);
